if (!snmp) return null;

const session = snmp.createSession(
    host,
    community || env.get('SNMP_COMMUNITY') || 'public',
    { port: port || 161, version: snmp.Version2c, retries: 1, timeout: 2000 }
);
//ตรวจสอบ อุปกรณ์ทำงานอยู่?
const nodeRef = node;
session.get(['1.3.6.1.2.1.1.3.0'], function (error, varbinds) {
    session.close();
    if (error) {
        nodeRef.warn(`Ping failed for ${host} (${mid}) - Skipping walkers`);
    } else {
        nodeRef.send([
            { machine_id: mid, topic: mid, _walker: 'cpu', payload: '', host, community, snmp_port: port },
            { machine_id: mid, topic: mid, _walker: 'storage', payload: '', host, community, snmp_port: port },
            { machine_id: mid, topic: mid, _walker: 'network', payload: '', host, community, snmp_port: port },
            { machine_id: mid, topic: mid, _walker: 'temp', payload: '', host, community, snmp_port: port },
            { machine_id: mid, topic: mid, _walker: 'ldi', payload: '', host, community, snmp_port: port }
        ]);
    }
});
return null;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { cpu: null }; return msg; }

const baseOid = '1.3.6.1.2.1.25.3.3.1.2';
const session = snmp.createSession(
    msg.host,
    msg.community || env.get('SNMP_COMMUNITY') || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 1, timeout: 2000 }
);

session.on('error', function (err) {
    msg._walker = 'cpu'; node.error('SNMP session error: ' + err.message, msg);
    session.close(); // CRITICAL FIX: Prevent UDP Port Leak
});

const nodeRef = node;
const msgRef = msg;
const results = [];

session.subtree(baseOid, 50, function (varbinds) {
    varbinds.forEach(item => {
        if (item.type !== 128 && item.type !== 129 && item.type !== 130) {
            let val = Number(item.value);
            if (!isNaN(val)) results.push(val);
        }
    });
}, function (error) {
    session.close();
    if (error) {
        msgRef._walker = 'cpu';
        nodeRef.error('SNMP error: ' + error.message, msgRef);
        msgRef.payload = { cpu: null };
    } else {
        let cores = results.length;
        let totalLoad = results.reduce((sum, val) => sum + Number(val), 0);
        let avgLoad = cores > 0 ? parseFloat((totalLoad / cores).toFixed(2)) : null;
        if (cores === 0) {
            msgRef.payload = { cpu: null };
        } else {
            msgRef.payload = { cpu: { cores: cores, load: avgLoad } };
        }
    }
    nodeRef.send(msgRef);
});
return null;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { disk: null }; return msg; }

const session = snmp.createSession(
    msg.host,
    msg.community || env.get('SNMP_COMMUNITY') || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 1, timeout: 2000 }
);

session.on('error', function (err) {
    msg._walker = 'storage'; node.error('SNMP session error: ' + err.message, msg);
    session.close(); // CRITICAL FIX: Prevent UDP Port Leak
});

const nodeRef = node;
const msgRef = msg;
const baseOid = '1.3.6.1.2.1.25.2.3.1';
const storageTemp = {};

session.subtree(baseOid, 50, function (varbinds) {
    varbinds.forEach(item => {
        if (item.type !== 129) {
            let oidStr = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
            let suffix = oidStr.replace(baseOid + '.', '');
            let parts = suffix.split('.');
            let prop = parts[0];
            let index = parts[1];

            if (!storageTemp[index]) {
                storageTemp[index] = { index: index };
            }
            let val = (Buffer.isBuffer(item.value)) ? item.value.toString('utf8') : item.value;
            if (prop === '2') storageTemp[index].type_oid = val;
            if (prop === '3') storageTemp[index].name = val;
            if (prop === '4') storageTemp[index].unit = parseInt(val);
            if (prop === '5') storageTemp[index].size = parseInt(val);
            if (prop === '6') storageTemp[index].used = parseInt(val);
        }
    });
}, function (error) {
    session.close();
    let result = { ramTotal: 0, ramUsed: 0, ramFree: 0, diskTotal: 0, diskUsed: 0, diskFree: 0, desc: {} };
    if (error) {
        msgRef._walker = 'storage';
        nodeRef.error('SNMP error: ' + error.message, msgRef);
        msgRef.payload = { disk: null };
    } else {
        let hasData = false;
        Object.values(storageTemp).forEach(device => {
            if (!device.name || device.size == null) return;
            hasData = true;
            let nameUpper = String(device.name).toUpperCase();
            let isRam = String(device.type_oid).includes('1.3.6.1.2.1.25.2.1.2');
            let sizeFixed = device.size < 0 ? device.size + 4294967296 : device.size;
            let totalBytes = (sizeFixed * (device.unit || 1));
            let usedFixed = device.used < 0 ? device.used + 4294967296 : device.used;
            let usedBytes = (usedFixed * (device.unit || 1));

            if (isRam) {
                result.ramTotal += totalBytes / (1024 * 1024);
                result.ramUsed += usedBytes / (1024 * 1024);
            } else {
                result.diskTotal += totalBytes / (1024 * 1024 * 1024);
                result.diskUsed += usedBytes / (1024 * 1024 * 1024);
                let gb = totalBytes / (1024 * 1024 * 1024);
                result.desc[device.name] = parseFloat(gb.toFixed(2));
            }
        });
        if (!hasData) {
            msgRef.payload = { disk: null };
        } else {
            result.ramTotal = parseFloat(result.ramTotal.toFixed(2));
            result.ramUsed = parseFloat(result.ramUsed.toFixed(2));
            result.ramFree = parseFloat((result.ramTotal - result.ramUsed).toFixed(2));
            result.diskTotal = parseFloat(result.diskTotal.toFixed(2));
            result.diskUsed = parseFloat(result.diskUsed.toFixed(2));
            result.diskFree = parseFloat((result.diskTotal - result.diskUsed).toFixed(2));
            msgRef.payload = { disk: result };
        }
    }
    nodeRef.send(msgRef);
});
return null;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { interfaces: [] }; return msg; }

const session = snmp.createSession(
    msg.host,
    msg.community || env.get('SNMP_COMMUNITY') || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 1, timeout: 2000 }
);

session.on('error', function (err) {
    msg._walker = 'network'; node.error('SNMP session error: ' + err.message, msg);
    session.close();
});

const nodeRef = node;
const msgRef = msg;
const now = Date.now();

const ifXTable = '1.3.6.1.2.1.31.1.1.1'; // 64-bit
const ifTable = '1.3.6.1.2.1.2.2.1'; // Status

const netTemp = {};

session.subtree(ifXTable, 50, function (varbinds) {
    varbinds.forEach(item => {
        if (item.type !== 129 && item.type !== 128) {
            let oidStr = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
            let parts = oidStr.replace(ifXTable + '.', '').split('.');
            let prop = parts[0];
            let index = parts[1];
            if (!netTemp[index]) netTemp[index] = { index: index };
            let val = item.value;

            if (prop === '1') {
                netTemp[index].name = Buffer.isBuffer(val) ? val.toString('utf8') : String(val);
            } else if (prop === '6' || prop === '10') {
                // Safely parse Counter64 to BigInt
                let bigVal = 0n;
                if (Buffer.isBuffer(val)) {
                    let hex = val.toString('hex');
                    if (hex) bigVal = BigInt('0x' + hex);
                } else if (typeof val === 'number' || typeof val === 'string') {
                    try { bigVal = BigInt(val); } catch(e){}
                }
                if (prop === '6') netTemp[index].hcIn = bigVal;
                if (prop === '10') netTemp[index].hcOut = bigVal;
            } else if (prop === '15') {
                netTemp[index].speed = Buffer.isBuffer(val) ? Number(val.toString('utf8')) : Number(val);
            }
        }
    });
}, function (error) {
    if (error) {
        session.close();
        msgRef._walker = 'network';
        nodeRef.error('SNMP error: ' + error.message, msgRef);
        msgRef.payload = { interfaces: [] };
        nodeRef.send(msgRef);
        return;
    }

    // Fetch ifTable for status
    session.subtree(ifTable, 50, function(varbinds2) {
        varbinds2.forEach(item => {
            if (item.type !== 129 && item.type !== 128) {
                let oidStr = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
                let parts = oidStr.replace(ifTable + '.', '').split('.');
                let prop = parts[0];
                let index = parts[1];
                if (netTemp[index]) {
                    let val = item.value;
                    if (prop === '8') netTemp[index].status = Number(val);
                    if (prop === '6') {
                        if (Buffer.isBuffer(val)) {
                            let hex = val.toString('hex');
                            netTemp[index].mac = hex.match(/.{1,2}/g) ? hex.match(/.{1,2}/g).join(':').toUpperCase() : "Unknown";
                        }
                    }
                }
            }
        });
    }, function(error2) {
        session.close();
        let interfaces = [];
        let prevNet = global.get('net_' + msgRef.host) || {};

        Object.values(netTemp).forEach(device => {
            if (!device.name) return;
            let nameUpper = String(device.name).toUpperCase();
            if (nameUpper.includes('LOOPBACK') || nameUpper.includes('VMWARE') || nameUpper.includes('VIRTUAL')) return;

            let hcIn = device.hcIn !== undefined ? device.hcIn : 0n;
            let hcOut = device.hcOut !== undefined ? device.hcOut : 0n;
            let rxMbps = 0;
            let txMbps = 0;

            if (prevNet[device.index]) {
                let prev = prevNet[device.index];
                let timeDiff = (now - prev.time) / 1000;
                if (timeDiff > 0) {
                    let prevHcIn = BigInt(prev.hcIn || "0");
                    let prevHcOut = BigInt(prev.hcOut || "0");

                    let rxDiff = Number(hcIn - prevHcIn);
                    let txDiff = Number(hcOut - prevHcOut);

                    // Handle 64-bit counter wraparound
                    if (rxDiff < 0) rxDiff = Number((18446744073709551615n - prevHcIn) + hcIn);
                    if (txDiff < 0) txDiff = Number((18446744073709551615n - prevHcOut) + hcOut);
                    if (rxDiff < 0) rxDiff = 0; 
                    if (txDiff < 0) txDiff = 0;

                    rxMbps = (rxDiff * 8) / (1000000 * timeDiff);
                    txMbps = (txDiff * 8) / (1000000 * timeDiff);
                }
            }
            // Store BigInt as strings to prevent JSON serialization crash
            prevNet[device.index] = { time: now, hcIn: hcIn.toString(), hcOut: hcOut.toString() };

            interfaces.push({
                name: device.name,
                status: (device.status === 1) ? 'ON' : 'OFF',
                received_MB: parseFloat(rxMbps.toFixed(2)),
                sent_MB: parseFloat(txMbps.toFixed(2)),
                speed_Mbps: device.speed || 0,
                mac_address: device.mac || "Unknown"
            });
        });

        const GC_TIMEOUT = 20 * 60 * 1000;
        Object.keys(prevNet).forEach(key => {
            if (now - prevNet[key].time > GC_TIMEOUT) delete prevNet[key];
        });
        global.set('net_' + msgRef.host, prevNet);
        msgRef.payload = { interfaces: interfaces };
        nodeRef.send(msgRef);
    });
});
return null;

