const nodeRef = node;
const msgRef = msg;
const oids = [
    '1.3.6.1.4.1.2021.13.16.2.1.7.0',
    '1.3.6.1.4.1.2021.13.16.2.1.7.1'
];

session.get(oids, function (error, varbinds) {
    session.close();
    if (error) {
        msgRef._walker = 'temp';
        nodeRef.error('SNMP error: ' + error.message, msgRef);
        msgRef.payload = { temp: null };
    } else {
        let maxTemp = -999;
        varbinds.forEach(item => {
            if (item.type !== 128 && item.type !== 129 && item.type !== 130) {
                let val = Buffer.isBuffer(item.value) ? item.value.toString('utf8') : item.value;
                val = Number(val);
                if (val > maxTemp) maxTemp = val;
            }
        });
        if (maxTemp === -999) {
            msgRef.payload = { temp: null };
        } else {
            if (maxTemp > 100 && maxTemp < 1000) maxTemp = maxTemp / 10; // deci-degrees
            else if (maxTemp >= 1000) maxTemp = maxTemp / 1000; // milli-degrees
            msgRef.payload = { temp: maxTemp };
        }
    }
    nodeRef.send(msgRef);
});
return null;

const snmp = global.get('snmp');
if (!snmp) { msg.payload = { ldi: null }; return msg; }

const session = snmp.createSession(
    msg.host,
    msg.community || env.get('SNMP_COMMUNITY') || 'public',
    { port: msg.snmp_port || 161, version: snmp.Version2c, retries: 1, timeout: 2000 }
