const nodeRef = node;
const msgRef = msg;
const oids = [
    '1.3.6.1.4.1.9999.1.1.0','1.3.6.1.4.1.9999.1.2.0',
    '1.3.6.1.4.1.9999.1.3.0','1.3.6.1.4.1.9999.1.4.2',
    '1.3.6.1.4.1.9999.1.4.5','1.3.6.1.4.1.9999.1.5.1',
    '1.3.6.1.4.1.9999.1.6.1','1.3.6.1.4.1.9999.1.7.1',
    '1.3.6.1.4.1.9999.2.1.0','1.3.6.1.4.1.9999.2.2.0'
];

session.get(oids, function (error, varbinds) {
    session.close();
    let ldi = { throughput: 0, temperature: 0, humidity: 0, pressure: 0, joule_effect: 0, power_watt: 0, vibration: 0, wifi_rssi: 0, wifi_snr: 0 };
    if (error) {
        msgRef._walker = 'ldi';
        nodeRef.error('SNMP error: ' + error.message, msgRef);
        msgRef.payload = { ldi: null };
    } else {
        let hasData = false;
        varbinds.forEach(item => {
            if (item.type !== 128 && item.type !== 129 && item.type !== 130) {
                hasData = true;
                let oidString = Array.isArray(item.oid) ? item.oid.join('.') : String(item.oid);
                let val = Buffer.isBuffer(item.value) ? item.value.toString('utf8') : item.value;
                val = Number(val);
                if (oidString.endsWith('.9999.1.1.0')) ldi.throughput = val;
                if (oidString.endsWith('.9999.1.2.0')) ldi.temperature = val;
                if (oidString.endsWith('.9999.1.3.0')) ldi.humidity = val;
                if (oidString.endsWith('.9999.1.4.2')) ldi.pressure = val;
                if (oidString.endsWith('.9999.1.4.5')) ldi.joule_effect = val;
                if (oidString.endsWith('.9999.1.5.1')) ldi.power_watt = val;
                if (oidString.endsWith('.9999.1.6.1')) ldi.vibration = val;
                if (oidString.endsWith('.9999.2.1.0')) ldi.wifi_rssi = val;
                if (oidString.endsWith('.9999.2.2.0')) ldi.wifi_snr = val;
            }
        });
        if (!hasData) {
            msgRef.payload = { ldi: null };
        } else {
            msgRef.payload = { ldi: ldi };
        }
    }
    nodeRef.send(msgRef);
});
return null;

const pool = global.get('pgPool');
if (!pool) { node.error('pgPool not available in global context'); return null; }

const sql = 'SELECT device_id AS machine_id, hostname, snmp_community AS community, snmp_port FROM public.devices WHERE enabled = true';

pool.query(sql, [], function(err, result) {
    if (err) { node.warn('Device Registry: ' + err.message + ' — using fallback defaults'); return; }

    const registry = {};
    if (result && result.rows) {
        result.rows.forEach(row => {
            registry[row.machine_id] = {
                hostname: row.hostname || row.machine_id,
                community: row.community ,
                snmp_port: row.snmp_port || 161
            };
        });
    }

    // REPLACE completely instead of Object.assign to remove disabled/deleted devices
    global.set('deviceRegistry', registry);
    node.log('Device registry loaded: ' + Object.keys(registry).length + ' devices');
});
return null;

// ป้องกันความผิดพลาดใน Production: ดรอปข้อความทิ้งถ้าไม่มี IP
if (!msg.host) {
    node.error("Missing host configuration for machine: " + (msg.machine_id || "Unknown"));
    return null;
}
return msg;

const BATCH_INTERVAL_SEC = 30;
const BUFFER_MAX = 500; 

try {
    if (!msg.payload || !Array.isArray(msg.payload)) return null;
    const deviceId = String(msg.topic || '').replace(/'/g, "''").trim();
    if (!deviceId) return null;

    // ── Phase 1 & 2: ประมวลผลข้อมูล ──────────────────────────────────────────
    const parsed = Object.assign({}, ...msg.payload);

    // ── Phase 3: เก็บลง GLOBAL Buffer (พร้อมระบบ Disk-Backed DLQ) ───────────
    const now = Date.now();
    const bufKey = `global_batch_buf`;
    const dlqFile = '/data/dlq_backup.json';
    const fs = global.get('fs');

    let buffer = global.get(bufKey);
    if (!buffer) {
        // ตรวจสอบว่ามีไฟล์ DLQ ค้างอยู่จากตอน Server ล่มไหม?
        if (fs && fs.existsSync(dlqFile)) {
            try {
                buffer = JSON.parse(fs.readFileSync(dlqFile, 'utf8'));
                node.warn(' Loaded DLQ from Disk! Recovering data...');
                fs.unlinkSync(dlqFile); // ลบทิ้งหลังโหลดเสร็จ
            } catch(e) {
                node.error('DLQ File corrupted, starting fresh');
                buffer = { sys: [], net: [], ldi: [], lastFlush: now };
            }
        } else {
            buffer = { sys: [], net: [], ldi: [], lastFlush: now };
        }
    }

    const currentTime = new Date().toISOString();

    if (parsed.cpu || parsed.disk || (parsed.temp !== null && parsed.temp !== undefined)) {
        if(parsed.cpu && isNaN(parsed.cpu.load)) parsed.cpu.load = 0;
        if(parsed.temp !== null && parsed.temp !== undefined && isNaN(parsed.temp)) parsed.temp = null;
        buffer.sys.push({
            time: currentTime, 
            device_id: deviceId,
            cpu_cores: parsed.cpu ? parsed.cpu.cores : null,
            cpu_load_percent: parsed.cpu ? parsed.cpu.load : null,
            ram_total_mb: parsed.disk ? parsed.disk.ramTotal : null,
            ram_used_mb: parsed.disk ? parsed.disk.ramUsed : null,
            ram_free_mb: parsed.disk ? parsed.disk.ramFree : null,
            disk_total_gb: parsed.disk ? parsed.disk.diskTotal : null,
            disk_used_gb: parsed.disk ? parsed.disk.diskUsed : null,
            disk_free_gb: parsed.disk ? parsed.disk.diskFree : null,
            disk_description: parsed.disk ? JSON.stringify(parsed.disk.desc || {}) : '{}',
            temp_c: (parsed.temp !== null && parsed.temp !== undefined) ? parsed.temp : null
        });
    }

    if (parsed.interfaces && Array.isArray(parsed.interfaces)) {
        parsed.interfaces.forEach(iface => {
            buffer.net.push({
                time: currentTime, 
                device_id: deviceId,
                iface_name: iface.name,
                rx_mbps: iface.received_MB || 0,
                tx_mbps: iface.sent_MB || 0,
                rx_errors: 0,
                tx_errors: 0,
                rx_drops: 0,
                tx_drops: 0, 
                status: iface.status === 'ON' ? 'UP' : 'DOWN'
            });
        });
    }

    if (parsed.ldi) {
        buffer.ldi.push({
            time: currentTime, 
            device_id: deviceId,
            throughput: parsed.ldi.throughput || 0,
            temperature: parsed.ldi.temperature || 0,
            humidity: parsed.ldi.humidity || 0,
            pressure: parsed.ldi.pressure || 0,
            joule_effect: parsed.ldi.joule_effect || 0,
            power_watt: parsed.ldi.power_watt || 0,
            vibration: parsed.ldi.vibration || 0,
            wifi_rssi: parsed.ldi.wifi_rssi || 0,
            wifi_snr: parsed.ldi.wifi_snr || 0
        });
    }

    const DLQ_LIMIT = 5000;
    // ── Phase 4: ตรวจสอบเงื่อนไขการส่งข้อมูล (Flush) ────────────────────────
    const elapsedSec = (now - buffer.lastFlush) / 1000;
    const totalItems = buffer.sys.length + buffer.net.length + buffer.ldi.length;

    if (elapsedSec < BATCH_INTERVAL_SEC && totalItems < BUFFER_MAX) {
        global.set(bufKey, buffer);
        return null;
    }

    const pool = global.get('pgPool');
    if (!pool) {
        node.error('pgPool is missing in global context!');
        return null;
    }

    // ตัดข้อมูลเก่าทิ้งถ้า DB พังนานเกินไป (FIFO DLQ)
    if (buffer.sys.length > DLQ_LIMIT) buffer.sys = buffer.sys.slice(-DLQ_LIMIT);
    if (buffer.net.length > DLQ_LIMIT) buffer.net = buffer.net.slice(-DLQ_LIMIT);
    if (buffer.ldi.length > DLQ_LIMIT) buffer.ldi = buffer.ldi.slice(-DLQ_LIMIT);

    // Snapshot ข้อมูลที่จะส่งรอบนี้ และเคลียร์ Global รอรับรอบใหม่ทันที
    const toInsert = { sys: [...buffer.sys], net: [...buffer.net], ldi: [...buffer.ldi] };
    global.set(bufKey, { sys: [], net: [], ldi: [], lastFlush: Date.now() });

    const queries = [
        ...buildQueries('public.sys_metrics', ['"time"', 'device_id', 'cpu_cores', 'cpu_load_percent', 'ram_total_mb', 'ram_used_mb', 'ram_free_mb', 'disk_total_gb', 'disk_used_gb', 'disk_free_gb', 'disk_description', 'temp_c'], toInsert.sys),
        ...buildQueries('public.net_metrics', ['"time"', 'device_id', 'iface_name', 'rx_mbps', 'tx_mbps', 'rx_errors', 'tx_errors', 'rx_drops', 'tx_drops', 'status'], toInsert.net),
        ...buildQueries('public.ldi_metrics', ['"time"', 'device_id', 'throughput', 'temperature', 'humidity', 'pressure', 'joule_effect', 'power_watt', 'vibration', 'wifi_rssi', 'wifi_snr'], toInsert.ldi)
    ];

    if (queries.length === 0) return null;

    Promise.allSettled(queries.map(q => pool.query(q.sql, q.params)))
        .then(results => {
            let failedSys = []; let failedNet = []; let failedLdi = [];
            results.forEach((res, i) => {
                if(res.status === 'rejected') {
                    node.error('DB Chunk Error: ' + res.reason.message);
                    // กู้คืนข้อมูลที่พังกลับเข้า DLQ
                    // เนื่องจาก queries เรียงตาม Sys -> Net -> LDI 
                    // เราต้อง Map กลับไปให้ถูก (เพื่อความง่าย โยนทุกอย่างที่ไม่ผ่านเข้า Sys/Net/LDI Queue รวม)
                    // (Implementation เบื้องต้น: โยน toInsert กลับไปทั้งหมดเพื่อป้องกันข้อมูลสูญหาย)
                    failedSys = toInsert.sys;
                    failedNet = toInsert.net;
                    failedLdi = toInsert.ldi;
                }
            });

            if (failedSys.length > 0 || failedNet.length > 0 || failedLdi.length > 0) {
                const currentBuffer = global.get(bufKey) || { sys: [], net: [], ldi: [], lastFlush: Date.now() };
                currentBuffer.sys = [...failedSys, ...currentBuffer.sys].slice(-DLQ_LIMIT);
                currentBuffer.net = [...failedNet, ...currentBuffer.net].slice(-DLQ_LIMIT);
                currentBuffer.ldi = [...failedLdi, ...currentBuffer.ldi].slice(-DLQ_LIMIT);
                global.set(bufKey, currentBuffer);
                if (fs) {
                    fs.writeFile(dlqFile, JSON.stringify(currentBuffer), () => {});
                }
            }
        })
        .catch(err => {
            node.error(` DB Outage! Disk-Backed Retry Queue Activated: ${err.message}`);
            // DLQ: เอาข้อมูลที่ส่งไม่ผ่าน กลับไปต่อท้ายคิวปัจจุบัน
            const currentBuffer = global.get(bufKey) || { sys: [], net: [], ldi: [], lastFlush: Date.now() };
            currentBuffer.sys = [...toInsert.sys, ...currentBuffer.sys];
            currentBuffer.net = [...toInsert.net, ...currentBuffer.net];
            currentBuffer.ldi = [...toInsert.ldi, ...currentBuffer.ldi];
            global.set(bufKey, currentBuffer);

            // เขียนลง Harddisk (Backup) ป้องกัน Node-RED ดับระหว่าง DB ล่ม
            if (fs) {
                fs.writeFile(dlqFile, JSON.stringify(currentBuffer), (fsErr) => {
                    if(fsErr) node.error('Failed to write DLQ to disk: ' + fsErr.message);
                });
            }
        });
    return null;

} catch (err) {
    node.error(`Parser Crash: ${err.message}`, msg);
    return null;
}

function buildQueries(tableName, columns, rows) {
    if (!rows || rows.length === 0) return [];
    const CHUNK_SIZE = 500;
    const results = [];
    for (let i = 0; i < rows.length; i += CHUNK_SIZE) {
        const chunk = rows.slice(i, i + CHUNK_SIZE);
        const params = [];
        const placeholders = chunk.map((row) => {
            const tokens = columns.map((col) => {
                const key = col.replace(/"/g, '');
                let val = row[key];
                if (val === null) return 'NULL';
                params.push(val);
                const paramIndex = params.length;
                return key === 'disk_description' ? `$${paramIndex}::jsonb` : `$${paramIndex}`;
            });
            return `(${tokens.join(',')})`;
        }).join(',');
        results.push({ sql: `INSERT INTO ${tableName} (${columns.join(',')}) VALUES ${placeholders}`, params });
    }
    return results;
}

const registry = global.get('deviceRegistry') || {};
const devices = Object.keys(registry).map(id => {
    return {
        machine_id: id,
        topic: id,
        host: registry[id].hostname,
        community: registry[id].community,
        snmp_port: registry[id].snmp_port
    };
});
if (devices.length === 0) return null;

// Batch devices to prevent Event Loop OOM and fit within 8 seconds
const targetDurationMs = 8000;
const tickMs = 25; // 25ms is safe for Node.js event loop
const ticks = targetDurationMs / tickMs;
const batchSize = Math.max(1, Math.ceil(devices.length / ticks));

let i = 0;
const interval = setInterval(() => {
    let sent = 0;
    while(sent < batchSize && i < devices.length) {
        node.send(devices[i]);
        i++;
        sent++;
    }
    if (i >= devices.length) {
        clearInterval(interval);
    }
}, tickMs);
return null;

